class Solution {
public:
    ListNode* removeZeroSumSublists(ListNode* head) {
        ListNode dummy(0);
        dummy.next = head;
        int prefix = 0;
        unordered_map<int, ListNode*> seen;
        seen[0] = &dummy;

        while (head) {
            prefix += head->val;
            if (seen.find(prefix) != seen.end()) {
                ListNode* node = seen[prefix];
                ListNode* tmp = node->next;
                int tmpPrefix = prefix + tmp->val;
                while (tmp != head) {
                    seen.erase(tmpPrefix);
                    tmp = tmp->next;
                    tmpPrefix += tmp->val;
                }
                node->next = head->next;
            } else {
                seen[prefix] = head;
            }
            head = head->next;
        }
        return dummy.next;
    }
};
